UPDATE /* @SQLID=SUB0202_0208-04_1#Sql002 */ T_JP_ORDER 
SET 
    SHUBETU = #{req.shubetu}
    ,CODE = #{req.code}
    ,MESSAGE = #{req.errMessage}
    ,UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    ,UPDATE_USER = #{req.updateUser}
    ,ACCEPT_DATE = #{req.orderDate}

        ,ACCEPT_TIME = #{req.orderTime}

WHERE
    IFA_ORDER_NO = TO_NUMBER(#{req.ifaOrderNo})
    AND IFA_ORDER_SUB_NO = TO_NUMBER(#{req.ifaOrderSubNo})
